INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53388a94-739c-4933-b6c3-541f5b59a040',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Error Handling — Exceptions vs Result Types and When to Use Each$escape$,
  $escape$C# exceptions are expensive: each throw allocates a stack trace and unwinds the call stack. For expected failure paths — validation, not-found, parse errors — this is the wrong tool. The Result<T> pattern (popularized by ErrorOr, FluentResults, or hand-rolled) makes failure a first-class return value, forcing callers to handle it at compile time.

Use exceptions for truly exceptional conditions: unrecoverable I/O failures, violated invariants, programmer errors. Use Result<T> for business logic that regularly fails: a user lookup that returns NotFound, a payment that gets declined.

Error propagation in C# is manual with Result — you chain .Map(), .Bind(), or use switch expressions. With OneOf or ErrorOr, you get discriminated union semantics without the boilerplate. The key discipline: never let a Result silently drop its error. Treat .Value access without checking IsError the same way you'd treat a null dereference — a bug.

For async pipelines, Result composes cleanly with Task<Result<T>>, avoiding exception-based control flow across await boundaries.$escape$,
  $escape$// Using ErrorOr (ErrorOr NuGet package)
public async Task<ErrorOr<UserDto>> GetUserAsync(Guid id)
{
    var user = await _db.Users.FindAsync(id);
    if (user is null)
        return Error.NotFound("User.NotFound", $"User {id} does not exist.");

    return _mapper.Map<UserDto>(user);
}

// Caller — forced to handle both branches
var result = await GetUserAsync(id);
return result.Match(
    user => Results.Ok(user),
    errors => Results.Problem(errors.First().Description)
);$escape$,
