INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '24c43d2c-b49b-40c7-a220-13d8244bd834',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Memory Management — GC, Spans, and Why You Don't Always Need the Heap$escape$,
  $escape$C#'s GC is a tracing, generational collector (Gen0/1/2 + LOH). Most allocations land in Gen0 and are collected cheaply, but pressure mounts fast with short-lived reference types. The key insight: stack allocations never touch the GC at all. `stackalloc` gives you a raw block on the stack; `Span<T>` wraps it safely with bounds checking. For struct types, value semantics mean copies, not references — no heap, no GC involvement, no pointer indirection. C# has no ownership model (unlike Rust), but `ref struct` enforces stack-only lifetime at compile time — the compiler blocks boxing or storing it on the heap. For large, temporary buffers, `ArrayPool<T>.Shared.Rent()` recycles heap arrays, slashing Gen0 pressure. `IDisposable` + `using` handles deterministic release of unmanaged resources (file handles, native memory via `NativeMemory.Alloc`). The GC handles managed memory; you own the unmanaged side entirely. Understanding this boundary — managed vs. unmanaged, stack vs. heap, GC-tracked vs. pooled — is where C# performance work actually happens.$escape$,
  $escape$// Stack allocation — zero GC pressure
Span<int> buffer = stackalloc int[128];
buffer[0] = 42;

// Pooled heap array — avoids Gen0 churn
var pool = ArrayPool<int>.Shared;
int[] rented = pool.Rent(1024);
try
{
    rented[0] = 99;
}
finally
{
    pool.Return(rented); // must return manually
}

// ref struct — compiler-enforced stack-only lifetime
ref struct StackOnly
{
    public Span<byte> Data;
}$escape$,
  $escape$csharp$escape$,
