INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2396d864-7ff9-407e-a66a-d858b92ecaac',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# NuGet Lock Files — Pinning, Versioning, and Auditing Dependencies$escape$,
  $escape$NuGet's lock file (`packages.lock.json`) gives you reproducible restores across machines and CI. Enable it per project with `<RestorePackagesWithLockFile>true</RestorePackagesWithLockFile>` in your `.csproj`, or globally via `Directory.Build.props`. Once generated, pass `--locked-mode` to `dotnet restore` in CI to fail fast if the lock file is stale — no silent version drift.

For version ranges, prefer `[1.2.3]` (exact pin) for third-party libs with breaking-change history, or `1.*` for internal packages you control. Avoid open-ended `*` in production .csproj files; it opts you into unreviewed updates on every restore.

For auditing, `dotnet list package --vulnerable` queries the NuGet vulnerability database and surfaces CVEs with severity levels. Pipe it into CI with `--include-transitive` to catch indirect threats. Pair this with Central Package Management (`Directory.Packages.props`) so version pins live in one file — a single PR changes a version across every project in a solution, and audits target one source of truth.$escape$,
  $escape$<PropertyGroup>
  <!-- Enable lock file -->
  <RestorePackagesWithLockFile>true</RestorePackagesWithLockFile>
</PropertyGroup>

<!-- Directory.Packages.props (Central Package Management) -->
<Project>
  <PropertyGroup>
    <ManagePackageVersionsCentrally>true</ManagePackageVersionsCentrally>
  </PropertyGroup>
  <ItemGroup>
    <PackageVersion Include="Dapper" Version="[2.1.35]" />
    <PackageVersion Include="Npgsql" Version="8.*" />
  </ItemGroup>
</Project>

<!-- CI: fail if lock file is out of date -->
<!-- dotnet restore --locked-mode -->
<!-- dotnet list package --vulnerable --include-transitive -->$escape$,
  $escape$csharp$escape$,
