INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f3eb0ed8-8be7-45a8-81b6-ae9cf53130ba',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Unit Testing — xUnit, AAA Pattern, and the Philosophy Behind Isolated Tests$escape$,
  $escape$C# unit tests live in a separate class library project referencing xUnit, Moq, and FluentAssertions via NuGet. Each test method carries a [Fact] attribute for single-path assertions or [Theory] + [InlineData] for parameterized cases. The Arrange-Act-Assert (AAA) pattern is the enforced convention: set up dependencies, invoke the SUT, assert outcomes — no mixing concerns.

The core philosophy is isolation: a unit test must never touch the database, filesystem, or network. Dependencies like IRepository or IEmailService are injected via constructor and swapped with Mock<T> objects. Use mock.Setup(x => x.Method()).Returns(value) to define behavior and mock.Verify() to assert interactions.

Avoid testing implementation details — test observable behavior through the public API. One assertion per test keeps failures diagnostic. FluentAssertions makes this readable: result.Should().BeEquivalentTo(expected). The dotnet test CLI runs the full suite; coverage is measured via coverlet. Keep tests fast (sub-millisecond), deterministic, and independent — any test should pass in isolation or in any order.$escape$,
  $escape$[Fact]
public async Task GetUser_ReturnsUser_WhenExists()
{
    // Arrange
    var repo = new Mock<IUserRepository>();
    repo.Setup(r => r.GetByIdAsync(1)).ReturnsAsync(new User { Id = 1, Name = "Alice" });
    var sut = new UserService(repo.Object);

    // Act
    var result = await sut.GetUserAsync(1);

    // Assert
    result.Should().NotBeNull();
    result!.Name.Should().Be("Alice");
    repo.Verify(r => r.GetByIdAsync(1), Times.Once);
}$escape$,
  $escape$csharp$escape$,
