INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f96e4f88-a966-4b7d-a61a-a02cb104d7a7',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Benchmarking with BenchmarkDotNet — Beyond Stopwatch$escape$,
  $escape$Stopwatch-based timing is unreliable for micro-benchmarks in C#. The JIT warm-up phase, GC collections, and CPU branch prediction all skew naive measurements. BenchmarkDotNet eliminates this noise by running multiple iterations, controlling JIT compilation, and reporting allocations alongside throughput.

Decorate methods with [Benchmark] and run via BenchmarkRunner.Run<T>(). Add [MemoryDiagnoser] to capture heap allocations per operation — critical when comparing LINQ chains against manual loops, or string interpolation against StringBuilder. Use [Params] to test across input sizes and surface O(n) regressions automatically.

For runtime profiling beyond benchmarks, dotnet-trace captures ETW/EventPipe events without attaching a debugger. Combine with dotnet-counters to watch GC heap size, threadpool queue depth, and exception rates live in production. PerfView remains the gold standard for CPU flame graphs and GC allocation stacks on Windows. The [DisassemblyDiagnoser] attribute in BenchmarkDotNet lets you inspect JIT-emitted assembly directly — indispensable when verifying that Span<T> optimizations or AggressiveInlining hints actually take effect.$escape$,
  $escape$[MemoryDiagnoser]
[DisassemblyDiagnoser(maxDepth: 2)]
public class StringConcatBenchmark
{
    private static readonly string[] _parts = ["foo", "bar", "baz", "qux"];

    [Benchmark(Baseline = true)]
    public string Interpolation() => $"{_parts[0]}{_parts[1]}{_parts[2]}{_parts[3]}";

    [Benchmark]
    public string StringCreate() =>
        string.Create(12, _parts, (span, p) =>
        {
            var pos = 0;
            foreach (var s in p) { s.AsSpan().CopyTo(span[pos..]); pos += s.Length; }
        });
}$escape$,
  $escape$csharp$escape$,
