INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f845af62-4d31-4a85-90a5-1a22437a22f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Standard Library — What .NET Gives You Free vs What Needs a NuGet Package$escape$,
  $escape$The .NET BCL covers more ground than most developers realize, which means unnecessary NuGet dependencies sneak into projects.

Built-in and often overlooked: `System.Text.Json` (fast, AOT-safe JSON since .NET Core 3.1), `HttpClient` with `IHttpClientFactory`, `System.Security.Cryptography` (AES, RSA, HMACSHA256), `Channel<T>` for producer-consumer pipelines, `System.Threading.RateLimiting` (token bucket, sliding window — .NET 7+), and `Microsoft.Extensions.DependencyInjection` plus `ILogger<T>` as first-class citizens.

Still legitimately third-party: **Polly** for retry/circuit-breaker policies beyond the basic `Microsoft.Extensions.Http.Resilience` wrapper, **FluentValidation** for rule-based validation (`DataAnnotations` won't scale), **Mapster** or **AutoMapper** for object mapping (no built-in mapper exists), **CsvHelper** for CSV (no BCL equivalent), and **Serilog**/**NLog** for structured log sinks — `ILogger<T>` is just an abstraction.

The trap: reaching for `Newtonsoft.Json` by habit. `System.Text.Json` handles 95% of cases. Use `JsonSerializerOptions` with `ReferenceHandler.Preserve` or source generators before adding 500KB of Json.NET.$escape$,
  $escape$// Built-in rate limiting — no Polly needed for simple cases
using System.Threading.RateLimiting;

var limiter = new TokenBucketRateLimiter(new TokenBucketRateLimiterOptions
{
    TokenLimit = 100,
    ReplenishmentPeriod = TimeSpan.FromSeconds(1),
    TokensPerPeriod = 10,
    QueueProcessingOrder = QueueProcessingOrder.OldestFirst
});

await using var lease = await limiter.AcquireAsync(permitCount: 1);
if (lease.IsAcquired)
    await ProcessRequestAsync();$escape$,
  $escape$csharp$escape$,
