INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea8523b7-aa54-418e-a1fa-0926e2098852',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Dev Tooling — REPL, Debugger, and LSP Support You Should Actually Be Using$escape$,
  $escape$C# Interactive (csi.exe) ships with the .NET SDK and gives you a full REPL with access to NuGet packages via #r "nuget:Newtonsoft.Json". It supports multi-line expressions, top-level statements, and full IntelliSense when used inside Visual Studio's C# Interactive window. For scripting, .csx files run via dotnet-script give you the same experience with a shebang line.

The C# language server is Roslyn-backed OmniSharp or the newer roslyn LSP server (Microsoft.CodeAnalysis.LanguageServer), which powers VS Code's C# Dev Kit. The LSP server exposes go-to-definition, find-all-references, rename, and real-time diagnostics via the standard LSP protocol — meaning any LSP-compatible editor (Neovim, Helix, Zed) gets first-class C# support.

For debugging outside Visual Studio, use netcoredbg with the DAP (Debug Adapter Protocol) — it integrates with VS Code's launch.json and supports conditional breakpoints, expression evaluation, and step-into for async state machines. Pair it with MADGE or dotnet-trace for sampling CPU profiles without attaching a full debugger.$escape$,
  $escape$#!/usr/bin/env dotnet-script
#r "nuget:Dapper, 2.1.35"
#r "nuget:Npgsql, 8.0.3"

using Dapper;
using Npgsql;

await using var conn = new NpgsqlConnection("Host=localhost;Database=dev;Username=postgres");
var rows = await conn.QueryAsync<dynamic>("SELECT id, name FROM users LIMIT 5");

foreach (var row in rows)
    Console.WriteLine($"{row.id}: {row.name}");$escape$,
  $escape$csharp$escape$,
