INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad234d90-6266-4a6c-8881-8605423a08c3',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# JIT vs NativeAOT — Cold Starts, Startup Time, and When to Use Each$escape$,
  $escape$C# compiles to CIL (Common Intermediate Language), not native machine code. At runtime, RyuJIT translates CIL to native instructions on first execution. Startup involves two phases: assembly loading and JIT-compiling hot paths. Tiered compilation (default since .NET Core 3.0) mitigates this by generating fast Tier 0 code initially, then recompiling hot methods as optimized Tier 1 in the background.

For Azure Functions or CLI tools, JIT cold starts are real — .NET 8 functions can take 1–3 seconds cold. Two alternatives exist:

**ReadyToRun (R2R):** Pre-compiles IL to native at publish time, retaining a CIL fallback. Reduces JIT overhead ~30–40% but still requires the CLR. Safe for apps using reflection.

**NativeAOT (.NET 7+):** Produces a fully self-contained native binary. Startup drops below 10ms, no JIT, no CLR — but dynamic reflection, `Assembly.Load`, and `Activator.CreateInstance` are restricted or unavailable.

Use R2R for ASP.NET Core APIs where reflection-heavy middleware (EF Core, Swagger) is in play. Use NativeAOT for CLIs, serverless lambdas, or latency-sensitive edge workloads where cold start budget is under 50ms.$escape$,
  $escape$// .csproj — choose your compilation strategy
// <PublishReadyToRun>true</PublishReadyToRun>  // R2R: partial AOT, CLR required
// <PublishAot>true</PublishAot>                // NativeAOT: fully native, no CLR

using System.Runtime.InteropServices;

bool isNativeAot = !RuntimeFeature.IsDynamicCodeSupported;
Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"NativeAOT: {isNativeAot}");
Console.WriteLine($"RID: {RuntimeInformation.RuntimeIdentifier}");

// Force Tier 1 JIT immediately on a hot method:
// [MethodImpl(MethodImplOptions.AggressiveOptimization)]
// Or disable tiering entirely: DOTNET_TieredCompilation=0$escape$,
  $escape$csharp$escape$,
