INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b0b640bd-81c4-45c2-871a-c90822c0880b',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Deployment — Shrinking Binaries, Containers, and Runtime Dependencies$escape$,
  $escape$C# gives you three deployment modes that dramatically affect image size and portability. Framework-dependent deployments (the default) produce tiny outputs (~1 MB) but require the .NET runtime on the host — fine for controlled environments, fragile elsewhere. Self-contained deployments bundle the runtime, ballooning output to ~70 MB, but eliminate the host dependency entirely. The sweet spot is combining `--self-contained true` with `PublishSingleFile` and IL trimming via `PublishTrimmed`, which can cut self-contained binaries down to ~20 MB by stripping unused assemblies.

In Docker, always use multi-stage builds: build in `mcr.microsoft.com/dotnet/sdk`, copy artifacts into `mcr.microsoft.com/dotnet/aspnet` (framework-dependent) or `mcr.microsoft.com/dotnet/runtime-deps` (self-contained + trimmed). The `runtime-deps` image is ~13 MB vs `aspnet` at ~220 MB. ReadyToRun (`PublishReadyToRun=true`) pre-JITs IL to native code, reducing cold-start latency at the cost of ~20% larger output — worth it for containerized APIs with frequent scale-out. Always pin image tags to digest hashes in production, not `latest`.$escape$,
  $escape$<Project Sdk="Microsoft.NET.Sdk.Web">
  <PropertyGroup>
    <TargetFramework>net8.0</TargetFramework>
    <PublishSingleFile>true</PublishSingleFile>
    <SelfContained>true</SelfContained>
    <RuntimeIdentifier>linux-x64</RuntimeIdentifier>
    <PublishTrimmed>true</PublishTrimmed>
    <PublishReadyToRun>true</PublishReadyToRun>
    <InvariantGlobalization>true</InvariantGlobalization>
  </PropertyGroup>
</Project>$escape$,
  $escape$csharp$escape$,
