INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd75c6e2c-7e27-4007-92d7-39901760cff0',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# — When It Dominates and Where It Falls Short$escape$,
  $escape$C# excels in enterprise backend systems, real-time applications, and cross-platform desktop/mobile via .NET MAUI. Its strong type system, async/await model, and LINQ make it exceptional for data-heavy APIs, financial services, and game development via Unity. ASP.NET Core Minimal APIs deliver benchmark-leading throughput — often outperforming Go in JSON serialization benchmarks on TechEmpower. Source generators and AOT compilation via NativeAOT close the startup-time gap against Go and Rust for serverless workloads. However, C# struggles where it matters: cold-start latency in AWS Lambda (without NativeAOT) can hit 1–3 seconds, making it a poor fit for high-frequency serverless triggers. Systems programming requiring manual memory control (device drivers, OS kernels) are non-starters — Rust or C++ own that space. Scripting and data science workflows feel unnatural; Python's ecosystem dominates there. If your workload is long-running, stateful, or enterprise-grade, C# is a top-tier choice. For ephemeral, memory-constrained, or shell-automation tasks, reach for something else.$escape$,
  $escape$// NativeAOT-compatible Minimal API — near-zero cold start
var builder = WebApplication.CreateSlimBuilder(args);
builder.Services.ConfigureHttpJsonOptions(o =>
    o.SerializerOptions.TypeInfoResolverChain.Insert(0, AppJsonContext.Default));

var app = builder.Build();
app.MapGet("/ping", () => new PingResponse("pong"));
app.Run();

record PingResponse(string Message);

[JsonSerializable(typeof(PingResponse))]
internal partial class AppJsonContext : JsonSerializerContext { }$escape$,
  $escape$csharp$escape$,
