INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a732a3ab-833c-4da5-9c92-5ce6e9344e23',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Roslyn Analyzers — Enforce Idioms Without Code Reviews$escape$,
  $escape$Roslyn analyzers enforce C#-specific idioms at compile time — no third-party linter needed. Drop a `.editorconfig` at your solution root and configure analyzer severity per rule. The highest-impact rules: `dotnet_style_prefer_is_null_check_over_reference_equality_method` enforces `is null` over `== null`, avoiding operator overload traps; `csharp_prefer_simple_using_statement` replaces `using` blocks with declarations (C# 8+); `dotnet_style_require_accessibility_modifiers` mandates explicit access modifiers. Set rules to `:error` to block CI merges, `:warning` for gradual adoption. Run `dotnet format --verify-no-changes` in CI to enforce formatting without side effects. StyleCop.Analyzers layers naming conventions and XML doc requirements on top. For suppressions, prefer `#pragma warning disable IDE0041 // <reason>` over `[SuppressMessage]` — it shows up clearly in diffs. Add `<AnalysisMode>All</AnalysisMode>` to your `.csproj` to opt into all CA*, IDE*, and SYSLIB* diagnostics. Start with `Recommended`, triage the warnings, then escalate critical rules to `:error`.$escape$,
  $escape$// Analyzer: IDE0041 — prefer is null over == null
// Bad: skips operator overload, semantics are ambiguous
if (conn == null) throw new InvalidOperationException();

// Good: pattern match, operator overload cannot interfere
if (conn is null) throw new InvalidOperationException();

// Analyzer: IDE0063 — simple using declaration (C# 8+)
// Bad:
using (var reader = new StreamReader(path)) { /* ... */ }

// Good:
using var reader = new StreamReader(path);

// .csproj — enable all built-in Roslyn diagnostics:
// <AnalysisMode>All</AnalysisMode>$escape$,
  $escape$csharp$escape$,
