INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '99eb5cc2-dd4a-4ee5-9138-5528cc547c77',
  '00000000-0000-0000-0000-000000000001',
  $escape$C# Production Monitoring — GC Pauses, Runtime Metrics, and EventPipe Profiling$escape$,
  $escape$Since .NET 8, the runtime automatically publishes metrics under the `System.Runtime` meter — heap size, GC pause ratio, threadpool queue length, exception count. Wire them into OpenTelemetry with a single `AddRuntimeInstrumentation()` call and they flow to Prometheus or Azure Monitor with zero custom code.

For GC pauses specifically, `GC.GetGCMemoryInfo()` returns `PauseTimePercentage` and per-generation pause durations after each collection — useful for alerting. When you need finer granularity, subscribe to `Microsoft-Windows-DotNETRuntime` via `EventListener` with the GC keyword (`0x1`) to capture `GCSuspendEEBegin`/`GCSuspendEEEnd` events and compute exact stop-the-world durations inline.

For production profiling without restart, `dotnet-trace collect --process-id <pid> --profile gc-verbose` streams ETW/EventPipe data to a `.nettrace` file you open in PerfView or SpeedScope. Pair with `dotnet-counters monitor --counters System.Runtime` for a live terminal dashboard. If Gen2 collection frequency spikes, check for LOH pressure — objects ≥85,000 bytes always land there and never compact by default unless you call `GCSettings.LargeObjectHeapCompactionMode = GCLargeObjectHeapCompactionMode.CompactOnce`.$escape$,
  $escape$using System.Diagnostics.Tracing;

public sealed class GcPauseListener : EventListener
{
    private long _suspendStart;

    protected override void OnEventSourceCreated(EventSource src)
    {
        if (src.Name == "Microsoft-Windows-DotNETRuntime")
            EnableEvents(src, EventLevel.Informational, (EventKeywords)0x1); // GC keyword
    }

    protected override void OnEventWritten(EventWrittenEventArgs e)
    {
        if (e.EventName == "GCSuspendEEBegin")
            _suspendStart = Stopwatch.GetTimestamp();
        else if (e.EventName == "GCSuspendEEEnd")
        {
            var pauseMs = Stopwatch.GetElapsedTime(_suspendStart).TotalMilliseconds;
            Console.WriteLine($"GC pause: {pauseMs:F2} ms | Gen {e.Payload![0]}");
        }
    }
}$escape$,
